1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	export function quote(input: { items: Array<{ type: string }> }): { premium: number } {
13	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
14	  const base = input.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
15	  return { premium: Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE) };
16	}
17	
18	export function claim(_input: unknown): unknown {
19	  return undefined;
20	}
